mapper.select:
SELECT wwi.入库危废明细编号, wwi.入库单编号, w.入库单号, w.入库时间, wwi.废物名称, wwi.废物代码, wwi.废物形态, wwi.基本计量单位, wwi.辅助计量单位, CASE WHEN wwi.辅助计量单位 IS NOT NULL AND wwi.辅助计量单位 != '' THEN 1 ELSE 0 END 是否启用辅助核算, wwi.实际收运数量, wwi.实际收运辅助数量, CASE WHEN wwi.实际收运数量 > 0 THEN '乙方' ELSE '甲方' END 付款方, wwi.备注 FROM WAREHOUSING_WASTE_ITEM wwi JOIN WAREHOUSING w ON wwi.入库单编号 = w.入库单编号 WHERE w.入库单号 IN
#{code}
ORDER BY w.入库时间 DESC, wwi.入库危废明细编号

SELECT wwi.废物名称, wwi.废物代码, SUM(wwi.实际收运数量) 总数量, wwi.基本计量单位, wwi.辅助计量单位, SUM(CASE WHEN wwi.辅助数量 IS NOT NULL THEN wwi.辅助数量 ELSE 0 END) 总辅助数量, CASE WHEN SUM(wwi.实际收运数量) > 0 THEN '乙方' ELSE '甲方' END 付款方, COUNT(*) 来源数量 FROM WAREHOUSING_WASTE_ITEM wwi JOIN WAREHOUSING w ON wwi.入库单编号 = w.入库单编号 WHERE w.入库单号 IN
#{code}
GROUP BY wwi.废物名称, wwi.废物代码, wwi.基本计量单位, wwi.辅助计量单位 ORDER BY wwi.废物代码

SELECT
    swd.*
FROM SETTLEMENT s
INNER JOIN SETTLEMENT_WASTE_DETAIL swd ON s.结算单编号 = swd.结算单编号
INNER JOIN SETTLEMENT_WASTE_INFO swi ON swd.明细编号 = swi.结算明细编号
WHERE s.合同号 = #{contractCode}
    AND s.状态 IN ('已审核', '已结算')
    AND swi.废物类别 = #{wasteCategory}
    AND swi.废物名称 = #{wasteName}
    AND swi.废物代码 = #{wasteCode}
ORDER BY s.审核时间 DESC
